/**
 * Extrae exclusivamente valores numéricos para:
 *  RES_NOMINAL, RES_UPPER, RES_LOWER,
 *  TURNS_NOMINAL, TURNS_UPPER, TURNS_LOWER
 *
 * - Detecta secciones SIN ":" (RES. OHMS, NUMBER OF TURNS).
 * - Lee subetiquetas NOMINAL/UPPER/LOWER con ":".
 * - Corta valores por el siguiente marcador o etiqueta.
 * - Convierte a number extrayendo el primer número válido (soporta decimales y signo).
 */
function parseResTurnsNumeric(text) {
  if (!text || typeof text !== 'string') return {};

  // Normalizaciones defensivas mínimas
  const normalizeColons = (s) => s.replace(/[\uFF1A\uFE55\u2236]/g, ':'); // variantes Unicode de ":"
  const src0 = normalizeColons(text).replace(/[\u00A0\t]+/g, ' '); // NBSP/tabs -> espacio

  // Unificamos a una sola línea para indexado sencillo
  const src = src0
    .replace(/\r\n/g, '\n')
    .replace(/\n+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  const out = {};

  // --- Helpers ---
  // Extrae el primer número del string (e.g., "95.0" -> 95, "UPPER: 104.5," -> 104.5)
  const toNumber = (s) => {
    const m = String(s).match(/[-+]?\d+(?:\.\d+)?/);
    return m ? Number(m[0]) : undefined;
  };

  const clean = (s) =>
    s.replace(/\s+/g, ' ')
     .replace(/[,\s]+$/g, '')
     .trim();

  // Marcadores de sección sin ":"
  const markerDefs = [
    { type: 'RES',   re: /\bRES\.?\s+OHMS\b/i },
    { type: 'TURNS', re: /\bNUMBER\s+OF\s+TURNS\b|\bTURNS\b/i }
  ];
  const markers = [];
  for (const def of markerDefs) {
    const m = def.re.exec(src);
    if (m) markers.push({ type: def.type, index: m.index });
  }
  markers.sort((a, b) => a.index - b.index);

  const currentSectionAt = (pos) => {
    let cur = null;
    for (const mk of markers) {
      if (mk.index <= pos) cur = mk.type;
      else break;
    }
    return cur; // 'RES' | 'TURNS' | null
  };

  // Localiza todas las etiquetas con ":" (NOMINAL, UPPER, LOWER)
  const labelRe = /([A-Z][A-Z0-9 .\/%+\-]*?):\s*/g;
  const labels = [];
  let lm;
  while ((lm = labelRe.exec(src)) !== null) {
    labels.push({
      label: lm[1].trim(),
      valueStart: labelRe.lastIndex,
      index: lm.index
    });
  }

  for (let i = 0; i < labels.length; i++) {
    const cur = labels[i];
    const next = labels[i + 1];

    // Corta por la siguiente etiqueta con ":" o por el próximo marcador de sección
    let end = next ? next.index : src.length;
    for (const mk of markers) {
      if (mk.index > cur.valueStart && mk.index < end) {
        end = mk.index;
        break;
      }
    }

    const label = cur.label.replace(/\s+/g, ' ').trim();
    const sect = currentSectionAt(cur.index);
    if (!sect) continue; // solo dentro de RES/TURNS

    const raw = clean(src.slice(cur.valueStart, end));
    if (!raw) continue;

    const num = toNumber(raw);
    if (typeof num !== 'number' || Number.isNaN(num)) continue;

    if (/^NOMINAL$/i.test(label)) {
      if (sect === 'RES')   out.resistance = num;
      if (sect === 'TURNS') out.turns = num;
      continue;
    }
    if (/^UPPER$/i.test(label)) {
      if (sect === 'RES')   out.resUpper = num;
      if (sect === 'TURNS') out.turnsUpper = num;
      continue;
    }
    if (/^LOWER$/i.test(label)) {
      if (sect === 'RES')   out.resLower = num;
      if (sect === 'TURNS') out.turnsLower = num;
      continue;
    }
  }

  return out;
}

