const chars = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';
const base = chars.length;

// Obtener el contador actual desde el contexto (inicializar si no existe)
let count = context.get('count') || 0;

// Calcular los dígitos
let first = Math.floor(count / base);
let second = count % base;

// Obtener el valor alfanumérico
let counterValue = chars[first] + chars[second];

// Incrementar y guardar el nuevo valor en el contexto
count++;
if (count >= base * base) {
    count = 0; // Reiniciar al llegar a "ZZ"
}
context.set('count', count);

// Enviar el valor alfanumérico en msg.payload
msg.payload = counterValue;
return msg;

// Caracteres válidos: 0-9 + A-Z
const chars = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ';
const base = chars.length; // Base 36

// Obtener el valor numérico de msg.payload (asegurarse de que sea un número)
let num = Number(msg.payload);

// Comprobar si el valor es un número válido
if (isNaN(num)) {
    node.error("El valor de msg.payload no es un número válido: " + msg.payload);
    return null;
}

// Convertir el número decimal a un formato alfanumérico
let counterValue = '';

// Si el número es 0, asignar directamente "0"
if (num === 0) {
    counterValue = chars[0];
} else {
    // Convertir el número a una cadena alfanumérica
    while (num > 0) {
        let remainder = num % base;  // Obtener el residuo
        counterValue = chars[remainder] + counterValue;  // Agregar el carácter correspondiente
        num = Math.floor(num / base);  // Dividir el número por la base
    }
}

// Enviar el valor alfanumérico en msg.payload
msg.payload = counterValue;

return msg;
